const express = require('express');
const app = express();
const bodyParser = require('body-parser');

app.use(bodyParser.json());

let rewards = [
  { level: 1, reward: '50 coins' },
  { level: 2, reward: '100 coins' },
  { level: 3, reward: '200 coins' }
];

app.post('/complete-level', (req, res) => {
  const { level, score, time } = req.body;

  if (!level || !score || !time) {
    return res.status(400).json({ message: 'Level, score, and time are required.' });
  }

  const reward = rewards.find(r => r.level === level);

  if (reward) {
    res.json({ message: `Congratulations! You earned ${reward.reward}.` });
  } else {
    res.status(404).json({ message: 'Reward not found for this level.' });
  }
});

app.post('/claim-reward', (req, res) => {
  const { rewardCode } = req.body;

  if (!rewardCode) {
    return res.status(400).json({ message: 'Reward code is required.' });
  }

  // Logic to verify the reward code and claim rewards

  res.json({ message: 'Reward claimed successfully!' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});